 66→pub(super) fn extract_voice_file(msg: &Message) -> Option<VoiceFileInfo> {
 67→    match &msg.kind {
 68→        MessageKind::Common(common) => match &common.media_kind {
 69→            MediaKind::Voice(v) => Some(VoiceFileInfo {
 70→                file_id: v.voice.file.id.clone(),
 71→                format: "ogg".to_string(),
 72→            }),
 73→            MediaKind::Audio(a) => {
 74→                let format = a
 75→                    .audio
 76→                    .mime_type
 77→                    .as_ref()
 78→                    .map(|m| match m.as_ref() {
 79→                        "audio/mpeg" | "audio/mp3" => "mp3",
 80→                        "audio/mp4" | "audio/m4a" | "audio/x-m4a" => "m4a",
 81→                        "audio/ogg" | "audio/opus" => "ogg",
 82→                        "audio/wav" | "audio/x-wav" => "wav",
 83→                        "audio/webm" => "webm",
 84→                        _ => "mp3",
 85→                    })
 86→                    .unwrap_or("mp3")
 87→                    .to_string();
 88→                Some(VoiceFileInfo {
 89→                    file_id: a.audio.file.id.clone(),
 90→                    format,
 91→                })
 92→            },
 93→            _ => None,
 94→        },
 95→        _ => None,
 96→    }
 97→}
