148→pub(super) fn format_document_label(file_name: Option<&str>, media_type: &str) -> String {
149→    match file_name {
150→        Some(name) if !name.trim().is_empty() => format!("[Document: {name} ({media_type})]"),
151→        _ => format!("[Document: {media_type}]"),
