155→pub(super) fn sanitize_document_filename(name: &str) -> String {
156→    let sanitized: String = name
157→        .chars()
158→        .filter(|c| c.is_ascii_alphanumeric() || *c == '-' || *c == '_' || *c == '.')
159→        .collect();
160→    sanitized.trim_start_matches('.').to_string()
161→}
