163→pub(super) fn build_saved_document_filename(
164→    file_name: Option<&str>,
165→    media_type: &str,
166→    file_id: &str,
167→) -> String {
168→    let ext = moltis_media::mime::extension_for_mime(media_type);
169→    let file_id_prefix: String = sanitize_document_filename(file_id)
170→        .chars()
171→        .take(16)
172→        .collect();
173→
174→    let base_name = file_name
175→        .map(str::trim)
176→        .filter(|name| !name.is_empty())
177→        .map(sanitize_document_filename)
178→        .filter(|name| !name.is_empty())
179→        .map(|name| {
180→            if name.contains('.') {
181→                name
182→            } else {
183→                format!("{name}.{ext}")
184→            }
185→        })
186→        .unwrap_or_else(|| format!("document.{ext}"));
187→
188→    if file_id_prefix.is_empty() {
189→        base_name
190→    } else {
191→        format!("{file_id_prefix}_{base_name}")
192→    }
193→}
