211→pub(super) fn build_document_body(
212→    caption: &str,
213→    doc_label: &str,
214→    extracted_text: Option<&str>,
215→) -> String {
216→    let mut sections = Vec::new();
217→    if !caption.is_empty() {
218→        sections.push(caption.to_string());
219→    }
220→    sections.push(doc_label.to_string());
221→    if let Some(text) = extracted_text
222→        .map(str::trim)
223→        .filter(|text| !text.is_empty())
224→    {
225→        sections.push(text.to_string());
226→    }
227→    sections.join("\n\n")
228→}
