239→pub(super) fn should_inline_document_text(media_type: &str) -> bool {
240→    matches!(
241→        media_type,
242→        "text/html"
243→            | "text/plain"
244→            | "text/markdown"
245→            | "text/x-markdown"
246→            | "text/xml"
247→            | "application/json"
248→            | "application/xml"
249→    ) || media_type.ends_with("+json")
250→        || media_type.ends_with("+xml")
251→}
