263→pub(super) fn truncate_inline_document_text(text: &str) -> Option<String> {
264→    let trimmed = text.trim();
265→    if trimmed.is_empty() {
266→        return None;
267→    }
268→
269→    let mut truncated = false;
270→    let mut text =
271→        if let Some((byte_idx, _)) = trimmed.char_indices().nth(MAX_INLINE_DOCUMENT_CHARS) {
272→            truncated = true;
273→            trimmed[..byte_idx].to_string()
274→        } else {
275→            trimmed.to_string()
276→        };
277→
278→    if truncated {
279→        text.push_str("\n\n[Document content truncated]");
280→    }
281→
282→    Some(text)
283→}
284→
285→pub(super) fn extract_text_document_content(data: &[u8], media_type: &str) -> Option<String> {
286→    if data.is_empty() || !should_inline_document_text(media_type) {
287→        return None;
288→    }
289→
290→    let byte_truncated = data.len() > MAX_INLINE_DOCUMENT_BYTES;
291→    let bounded = if byte_truncated {
292→        let slice = &data[..MAX_INLINE_DOCUMENT_BYTES];
293→        match std::str::from_utf8(slice) {
294→            Ok(_) => slice,
295→            Err(e) => &slice[..e.valid_up_to()],
296→        }
297→    } else {
298→        data
299→    };
300→
301→    let lossy = String::from_utf8_lossy(bounded);
302→    let mut text = truncate_inline_document_text(&lossy)?;
303→    if byte_truncated && !text.contains("[Document content truncated]") {
304→        text.push_str("\n\n[Document content truncated]");
305→    }
306→    Some(text)
307→}
