309→pub(super) async fn extract_pdf_document_content(data: Vec<u8>) -> Option<String> {
310→    let extracted = tokio::task::spawn_blocking(move || {
311→        use std::io::Write as _;
312→
313→        let mut file = tempfile::Builder::new().suffix(".pdf").tempfile().ok()?;
314→        file.write_all(&data).ok()?;
315→        pdf_extract::extract_text(file.path()).ok()
316→    })
317→    .await
318→    .ok()??;
319→    truncate_inline_document_text(&extracted)
320→}
