405→pub(super) async fn download_telegram_file(bot: &Bot, file_id: &str) -> Result<Vec<u8>> {
406→    let file = bot.get_file(file_id).await?;
407→    let token = bot.token();
408→    let base = bot.api_url();
409→    let url = format!("{base}file/bot{token}/{}", file.path);
410→
411→    let response = reqwest::get(&url).await?;
412→    if !response.status().is_success() {
413→        return Err(crate::Error::message(format!(
414→            "failed to download file: HTTP {}",
415→            response.status()
416→        )));
417→    }
418→
419→    let data = response.bytes().await?.to_vec();
420→    Ok(data)
421→}
