423→pub(super) fn classify_chat(msg: &Message) -> (ChatType, Option<String>) {
424→    match msg.chat.kind {
425→        teloxide::types::ChatKind::Private(_) => (ChatType::Dm, None),
426→        teloxide::types::ChatKind::Public(ref p) => {
427→            let group_id = msg.chat.id.0.to_string();
428→            match p.kind {
429→                teloxide::types::PublicChatKind::Channel(_) => (ChatType::Channel, Some(group_id)),
430→                _ => (ChatType::Group, Some(group_id)),
431→            }
432→        },
433→    }
434→}
