461→pub(super) const VOICE_REPLY_EMPTY_TRANSCRIPTION: &str =
462→    "I couldn't hear anything in that voice message. Could you try again or type it out?";
463→pub(super) const VOICE_REPLY_TRANSCRIPTION_FAILED: &str =
464→    "I couldn't transcribe your voice message. Could you try again or type it out?";
465→pub(super) const VOICE_REPLY_DOWNLOAD_FAILED: &str =
466→    "I couldn't download your voice message. Please try again.";
467→pub(super) const VOICE_REPLY_UNAVAILABLE: &str =
468→    "I received your voice message but voice processing is not available right now.";
469→pub(super) const VOICE_REPLY_STT_SETUP_HINT: &str =
470→    "I can't understand voice, you did not configure it, please visit Settings -> Voice";
