472→#[allow(clippy::too_many_arguments)]
473→pub(super) async fn handle_voice_message(
474→    bot: &Bot,
475→    msg: &Message,
476→    account_id: &str,
477→    caption: Option<&str>,
478→    event_sink: Option<&Arc<dyn ChannelEventSink>>,
479→    outbound: &dyn moltis_channels::ChannelOutbound,
480→    voice_file: &VoiceFileInfo,
481→) -> Option<(String, Vec<ChannelAttachment>, Option<(Vec<u8>, String)>)> {
482→    let caption_text = caption
483→        .map(str::trim)
484→        .filter(|s| !s.is_empty())
485→        .map(str::to_string);
486→
487→    let reply_target = outbound_to_for_msg(msg);
488→
489→    async fn send_direct_reply(
490→        outbound: &dyn moltis_channels::ChannelOutbound,
491→        account_id: &str,
492→        to: &str,
493→        text: &str,
494→    ) {
495→        if let Err(e) = outbound.send_text(account_id, to, text, None).await {
496→            warn!(account_id, "failed to send voice fallback reply: {e}");
497→        }
498→    }
499→
500→    let Some(sink) = event_sink else {
501→        warn!(
502→            account_id,
503→            "no event sink available for voice message; sending direct reply"
504→        );
505→        send_direct_reply(outbound, account_id, &reply_target, VOICE_REPLY_UNAVAILABLE).await;
506→        return None;
507→    };
508→
509→    if !sink.voice_stt_available().await {
510→        if let Some(caption) = caption_text {
511→            return Some((caption, Vec::new(), None));
512→        }
513→        if let Err(e) = outbound
514→            .send_text(account_id, &reply_target, VOICE_REPLY_STT_SETUP_HINT, None)
515→            .await
516→        {
517→            warn!(account_id, "failed to send STT setup hint: {e}");
518→        }
519→        return None;
520→    }
521→
522→    let audio_data = match download_telegram_file(bot, &voice_file.file_id).await {
523→        Ok(data) => data,
524→        Err(e) => {
525→            warn!(account_id, error = %e, "failed to download voice file");
526→            if let Some(caption) = caption_text {
527→                return Some((caption, Vec::new(), None));
528→            }
529→            send_direct_reply(
530→                outbound,
531→                account_id,
532→                &reply_target,
533→                VOICE_REPLY_DOWNLOAD_FAILED,
534→            )
535→            .await;
536→            return None;
537→        },
538→    };
539→
540→    debug!(
541→        account_id,
542→        file_id = %voice_file.file_id,
543→        format = %voice_file.format,
544→        size = audio_data.len(),
545→        "downloaded voice file, transcribing"
546→    );
547→    let saved_audio = Some((audio_data.clone(), voice_file.format.clone()));
548→
549→    match sink.transcribe_voice(&audio_data, &voice_file.format).await {
550→        Ok(transcribed) if transcribed.trim().is_empty() => {
551→            warn!(
552→                account_id,
553→                audio_size = audio_data.len(),
554→                "voice transcription returned empty text"
555→            );
556→            if let Some(caption) = caption_text {
557→                return Some((caption, Vec::new(), saved_audio));
558→            }
559→            send_direct_reply(
560→                outbound,
561→                account_id,
562→                &reply_target,
563→                VOICE_REPLY_EMPTY_TRANSCRIPTION,
564→            )
565→            .await;
566→            None
567→        },
568→        Ok(transcribed) => {
569→            debug!(
570→                account_id,
571→                text_len = transcribed.len(),
572→                "voice transcription successful"
573→            );
574→            let body = match caption_text {
575→                Some(caption) => format!("{caption}\n\n[Voice message]: {transcribed}"),
576→                None => transcribed,
577→            };
578→            Some((body, Vec::new(), saved_audio))
579→        },
580→        Err(e) => {
581→            warn!(account_id, error = %e, "voice transcription failed");
582→            if let Some(caption) = caption_text {
583→                return Some((caption, Vec::new(), saved_audio));
584→            }
585→            send_direct_reply(
586→                outbound,
587→                account_id,
588→                &reply_target,
589→                VOICE_REPLY_TRANSCRIPTION_FAILED,
590→            )
591→            .await;
592→            None
593→        },
594→    }
595→}
